using System.ComponentModel;
using System.Text;
using System.Text.Json;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;

// --- Configuration ---

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL")
    ?? "gpt-4o-mini-2024-07-18";

// --- Shared state ---

var notes = new List<ResearchNote>();

using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
httpClient.Timeout = TimeSpan.FromSeconds(15);

// --- Tool implementations ---

[Description("Search the web for information. Returns titles, URLs, and snippets.")]
async Task<string> SearchWeb(
    [Description("The search query")] string query)
{
    try
    {
        var encoded = Uri.EscapeDataString(query);
        var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
        var json = await httpClient.GetFromJsonAsync<JsonElement>(url);

        var sb = new StringBuilder();

        var abstractText = json.GetProperty("AbstractText").GetString();
        var abstractSource = json.GetProperty("AbstractSource").GetString();
        var abstractUrl = json.GetProperty("AbstractURL").GetString();
        if (!string.IsNullOrWhiteSpace(abstractText))
        {
            sb.AppendLine($"## {abstractSource}");
            sb.AppendLine($"URL: {abstractUrl}");
            sb.AppendLine(abstractText);
            sb.AppendLine();
        }

        if (json.TryGetProperty("RelatedTopics", out var topics))
        {
            var count = 0;
            foreach (var topic in topics.EnumerateArray())
            {
                if (count >= 8) break;
                var text = topic.TryGetProperty("Text", out var t) ? t.GetString() : null;
                var firstUrl = topic.TryGetProperty("FirstURL", out var u) ? u.GetString() : null;
                if (!string.IsNullOrWhiteSpace(text))
                {
                    sb.AppendLine($"- {text}");
                    if (!string.IsNullOrWhiteSpace(firstUrl))
                        sb.AppendLine($"  URL: {firstUrl}");
                    count++;
                }
            }
        }

        return sb.Length > 0
            ? sb.ToString()
            : $"No results found for '{query}'. Try different search terms.";
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}";
    }
}

[Description("Fetch and extract text content from a web page URL.")]
async Task<string> FetchWebPage(
    [Description("The full URL to fetch")] string url)
{
    try
    {
        var html = await httpClient.GetStringAsync(url);
        var text = Regex.Replace(html, "<script[^>]*>[\\s\\S]*?</script>", " ");
        text = Regex.Replace(text, "<style[^>]*>[\\s\\S]*?</style>", " ");
        text = Regex.Replace(text, "<[^>]+>", " ");
        text = System.Net.WebUtility.HtmlDecode(text);
        text = Regex.Replace(text, @"\s+", " ").Trim();

        const int maxLength = 4000;
        return text.Length > maxLength ? text[..maxLength] + "..." : text;
    }
    catch (Exception ex)
    {
        return $"Failed to fetch page: {ex.Message}";
    }
}

[Description("Save a research note to record a key finding or fact.")]
string SaveNote(
    [Description("Short title for the note")] string title,
    [Description("The note content — facts, data, or insights")] string content)
{
    notes.Add(new ResearchNote(title, content, DateTime.UtcNow));
    return $"Note #{notes.Count} saved: \"{title}\"";
}

[Description("Retrieve all research notes saved so far in this session.")]
string GetNotes()
{
    if (notes.Count == 0)
        return "No notes saved yet.";

    var sb = new StringBuilder();
    for (var i = 0; i < notes.Count; i++)
    {
        sb.AppendLine($"### Note {i + 1}: {notes[i].Title}");
        sb.AppendLine(notes[i].Content);
        sb.AppendLine();
    }
    return sb.ToString();
}

// --- Build the agent ---

var tools = new List<AITool>
{
    AIFunctionFactory.Create(SearchWeb),
    AIFunctionFactory.Create(FetchWebPage),
    AIFunctionFactory.Create(SaveNote),
    AIFunctionFactory.Create(GetNotes),
};

IChatClient chatClient = new OpenAI.OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

var agent = chatClient.AsAIAgent(
    new ChatClientAgentOptions
    {
        Name = "ResearchAgent",
        Description = "Researches topics by searching the web and taking structured notes",
        ChatOptions = new ChatOptions
        {
            Temperature = 0.2f,
            MaxOutputTokens = 4096,
            Tools = [.. tools],
        },
    });

const string instructions = """
    You are a research agent. Your job is to thoroughly research the given topic.

    Follow this process:
    1. Search the web with multiple varied queries to cover different angles of the topic.
    2. When search results reference useful URLs, fetch those pages for deeper detail.
    3. As you discover key facts, statistics, or insights, save each as a note using SaveNote.
    4. After gathering enough information (aim for at least 3 notes), call GetNotes to review
       everything you've collected, then compose a well-structured summary.

    Guidelines:
    - Use specific, targeted search queries — not vague ones.
    - Save notes incrementally as you learn things, don't wait until the end.
    - Your final summary should be comprehensive, citing the sources where you found information.
    """;

// --- Interactive loop ---

Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       🔍 AI Research Agent           ║");
Console.WriteLine("╠══════════════════════════════════════╣");
Console.WriteLine("║  Enter a topic to research.          ║");
Console.WriteLine("║  Type 'quit' to exit.                ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.Write("Research topic: ");
    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    notes.Clear();
    Console.WriteLine($"\n🔬 Researching: {topic}\n");

    var session = await agent.CreateSessionAsync();

    var runOptions = new ChatClientAgentRunOptions(new ChatOptions
    {
        Temperature = 0.2f,
        MaxOutputTokens = 4096,
    });

    await foreach (var update in agent.RunStreamingAsync(
        $"{instructions}\n\nResearch this topic and provide a comprehensive summary: {topic}",
        session,
        runOptions))
    {
        if (!string.IsNullOrEmpty(update.Text))
            Console.Write(update.Text);
    }

    Console.WriteLine("\n");
    if (notes.Count > 0)
        Console.WriteLine($"📝 {notes.Count} research note(s) were saved during this session.\n");
}

Console.WriteLine("Goodbye!");

// --- Types ---

record ResearchNote(string Title, string Content, DateTime CreatedAt);

using System.ComponentModel;
using System.Text;
using System.Text.Json;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
